class TaskQueue:
    def __init__(self):
        self.tasks = []

    def add_task(self, task):
        self.tasks.append(task)

    def run_all(self):
        results = []
        for task in self.tasks:
            results.append(task())
        self.tasks.clear()  # BUG: modifies during implicit reference
        return results
